import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"网银与电汇入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/online-banking-and-wire.md","filePath":"zh-CN/deposit/online-banking-and-wire.md"}'),o={name:"deposit/online-banking-and-wire.md"};function n(i,t,l,s,h,p){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="网银与电汇入金" tabindex="-1">网银与电汇入金 <a class="header-anchor" href="#网银与电汇入金" aria-label="Permalink to &quot;网银与电汇入金&quot;">​</a></h1><p>通过手机银行或网上银行将资金转账至长桥新加坡收款账户，新加坡本地转账和跨境电汇均通过此方式操作，转账完成后需上传汇款凭证。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>新加坡元（SGD）、美元（USD）、港元（HKD）</td></tr><tr><td>到账时间</td><td>预计 1–3 个交易日</td></tr><tr><td>手续费</td><td>长桥及代理银行（DBS）免费；汇款银行和中转银行可能收取约 200 HKD 或 25 USD</td></tr></tbody></table><h2 id="收款银行信息" tabindex="-1">收款银行信息 <a class="header-anchor" href="#收款银行信息" aria-label="Permalink to &quot;收款银行信息&quot;">​</a></h2><p><strong>新加坡本地转账（FAST）及国际电汇（SWIFT）</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>内容</th></tr></thead><tbody><tr><td>收款人姓名</td><td>LONG BRIDGE SEC</td></tr><tr><td>收款人账号</td><td>0725885663</td></tr><tr><td>收款银行</td><td>DBS BANK LTD</td></tr><tr><td>SWIFT 代码</td><td>DBSSSGSGXXX</td></tr><tr><td>附言（汇款备注）</td><td>填写证券账户号（如 SG10039100），<strong>必填</strong></td></tr></tbody></table><p>费用承担方：SHA（各环节各自扣除）</p><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>打开长桥 App，进入<strong>资产 → 存入资金 → 选择入金币种</strong>，查看收款银行信息</li><li>在银行手机端或网页端完成转账操作</li><li>保留汇款凭证截图</li><li>返回长桥 App，上传汇款凭证</li></ol><blockquote><p>完成转账后请立即上传凭证，否则影响入金进度。</p></blockquote><h2 id="特殊情况说明" tabindex="-1">特殊情况说明 <a class="header-anchor" href="#特殊情况说明" aria-label="Permalink to &quot;特殊情况说明&quot;">​</a></h2><p><strong>iFAST Global Bank（奕丰环球银行）</strong>：属于跨境电汇，因使用第三方支付平台，收款行可能无法解析付款方信息，需在长桥上传 iFAST 开户证明及汇款流水。</p><p><strong>IBAN</strong>：海外银行卡可在银行账户处直接输入 IBAN Code，不了解 IBAN 可查询银行结单获取。</p><p><strong>三位数银行代码</strong>：主要用于香港地区，海外银行卡没有银行代码时可填写 000。</p><p><strong>中转行显示问题</strong>：跨境电汇资金可能显示为中转行账户，如遇此情况请联系客服。</p><h2 id="同名账户要求与中转行说明" tabindex="-1">同名账户要求与中转行说明 <a class="header-anchor" href="#同名账户要求与中转行说明" aria-label="Permalink to &quot;同名账户要求与中转行说明&quot;">​</a></h2><ul><li>转账银行账户名必须与长桥证券账户名同名，不可使用他人或联名账户</li><li>银行通知「已汇出」不等于长桥已收款，资金到达后需结算与审批</li><li>节假日不处理汇款业务，请预留时间</li><li>不接受直接存入现金</li></ul>',17)])])}const S=a(o,[["render",n]]);export{c as __pageData,S as default};
